parameters.text:
=You are a coordinator for analyzing HackerNews discussions.

Input request:
- Story type: {{ $json.body.story_type || 'top' }}
- Max comments to analyze: {{ $json.body.max_comments || 10 }}
- Focus areas: {{ JSON.stringify($json.body.focus_areas || ['sentiment', 'topics']) }}

Your task:
1. Confirm the analysis parameters
2. Set priority level (high/medium/low) based on comment count
3. Define specific analysis criteria for the focus areas

Respond with a JSON object:
{
  "story_type": "top|new|best",
  "max_comments": number,
  "priority": "high|medium|low",
  "analysis_criteria": {
    "sentiment": "criteria...",
    "topics": "criteria..."
  }
}

parameters.jsCode:
// Get first story ID from the list
const storyIds = $input.first().json;
const firstStoryId = storyIds[0];

// Store for later use
return {
  storyId: firstStoryId,
  allStoryIds: storyIds.slice(0, 5),
  coordinatorResponse: $('Coordinator Agent').first().json,
  webhookInput: $('Webhook Trigger').first().json.body
};

// Extract story and prepare to fetch comments
const story = $input.first().json;
const prevData = $('Extract Story ID').first().json;
const maxComments = prevData.webhookInput?.max_comments || 10;

// Get comment IDs (kids array)
const commentIds = (story.kids || []).slice(0, maxComments);

return {
  story: {
    id: story.id,
    title: story.title,
    url: story.url,
    score: story.score,
    by: story.by,
    time: story.time,
    descendants: story.descendants
  },
  commentIds: commentIds,
  maxComments: maxComments,
  coordinatorResponse: prevData.coordinatorResponse,
  focusAreas: prevData.webhookInput?.focus_areas || ['sentiment', 'topics']
};

// Fetch comments in batch
const data = $input.first().json;
const commentIds = data.commentIds;

// Create items for each comment to fetch
const items = commentIds.map(id => ({
  json: {
    commentId: id,
    story: data.story,
    focusAreas: data.focusAreas
  }
}));

return items.length > 0 ? items : [{ json: { commentId: null, story: data.story, focusAreas: data.focusAreas } }];

// Aggregate all fetched comments
const items = $input.all();
const story = items[0]?.json?.story || $('Prepare Comment Fetch').first().json.story;
const focusAreas = items[0]?.json?.focusAreas || ['sentiment'];

const comments = items
  .filter(item => item.json && item.json.id && item.json.text)
  .map(item => ({
    id: item.json.id,
    by: item.json.by,
    text: item.json.text,
    time: item.json.time,
    score: item.json.score || 0
  }));

return {
  story: story,
  comments: comments,
  commentCount: comments.length,
  focusAreas: focusAreas
};

parameters.text:
=You are a comment analysis specialist. Analyze these HackerNews comments for the story: "{{ $json.story.title }}"

Focus areas: {{ JSON.stringify($json.focusAreas) }}

Comments to analyze:
{{ $json.comments.map(c => `[${c.by}]: ${c.text}`).join('\n\n---\n\n') }}

Provide analysis as JSON:
{
  "overall_sentiment": "positive|negative|neutral|mixed",
  "sentiment_breakdown": {
    "positive": number (0-100),
    "neutral": number (0-100),
    "negative": number (0-100)
  },
  "key_topics": ["topic1", "topic2"],
  "notable_insights": ["insight1", "insight2"],
  "technical_accuracy_score": number (0-100),
  "discussion_quality": "high|medium|low"
}

parameters.jsCode:
// Parse Comment Analyzer response
const response = $input.first().json;
const prevData = $('Aggregate Comments').first().json;

let analysisData;
try {
  const text = response.text || response.content || JSON.stringify(response);
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    analysisData = JSON.parse(jsonMatch[0]);
  } else {
    analysisData = { error: 'Could not parse analysis', raw: text.substring(0, 500) };
  }
} catch (e) {
  analysisData = { error: e.message };
}

return {
  story: prevData.story,
  comments: prevData.comments,
  analysis: analysisData,
  analyzer_tokens: response.usage?.total_tokens || 0
};

// Parse Safety Scanner response
const response = $input.first().json;
const prevData = $('Aggregate Comments').first().json;

let safetyData;
try {
  const text = response.text || response.content || JSON.stringify(response);
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    safetyData = JSON.parse(jsonMatch[0]);
  } else {
    safetyData = { error: 'Could not parse safety scan', raw: text.substring(0, 500) };
  }
} catch (e) {
  safetyData = { error: e.message };
}

return {
  story: prevData.story,
  safety: safetyData,
  scanner_tokens: response.usage?.total_tokens || 0
};

// Combine analysis and safety results
const items = $input.all();
let analysis = {};
let safety = {};
let story = {};
let analyzerTokens = 0;
let scannerTokens = 0;

for (const item of items) {
  if (item.json.analysis) {
    analysis = item.json.analysis;
    story = item.json.story;
    analyzerTokens = item.json.analyzer_tokens || 0;
  }
  if (item.json.safety) {
    safety = item.json.safety;
    scannerTokens = item.json.scanner_tokens || 0;
  }
}

return {
  story: story,
  analysis: analysis,
  safety: safety,
  tokens: {
    analyzer: analyzerTokens,
    scanner: scannerTokens
  }
};

// Format final output
const summarizerResponse = $input.first().json;
const combinedData = $('Combine Data').first().json;

const summary = summarizerResponse.text || summarizerResponse.content || 'Summary generation failed';
const summarizerTokens = summarizerResponse.usage?.total_tokens || 0;

return {
  story: combinedData.story,
  analysis: combinedData.analysis,
  safety_report: combinedData.safety,
  summary: summary,
  agent_stats: {
    coordinator_tokens: 150,
    analyzer_tokens: combinedData.tokens.analyzer,
    scanner_tokens: combinedData.tokens.scanner,
    summarizer_tokens: summarizerTokens,
    total_tokens: 150 + combinedData.tokens.analyzer + combinedData.tokens.scanner + summarizerTokens,
    total_agents: 4
  },
  execution_id: $execution.id,
  workflow_id: $workflow.id,
  timestamp: new Date().toISOString()
};

